from dataclasses import dataclass, field
from typing import Optional
import queue

@dataclass
class Message:
    sender: str
    recipient: str       # agent name, or 'broadcast'
    performative: str   # 'request' | 'inform' | 'query' | 'confirm' | 'refuse'
    content: dict
    reply_to: Optional[str] = None

class MessageBus:
    def __init__(self):
        self._queues: dict = {}

    def register(self, agent_name):
        self._queues[agent_name] = queue.Queue()

    def send(self, msg):
        if msg.recipient == 'broadcast':
            for q in self._queues.values():
                q.put(msg)
        elif msg.recipient in self._queues:
            self._queues[msg.recipient].put(msg)
        else:
            raise KeyError('Unknown recipient: ' + msg.recipient)

    def receive(self, agent_name, block=False, timeout=1.0):
        try:
            return self._queues[agent_name].get(block=block, timeout=timeout)
        except queue.Empty:
            return None

bus = MessageBus()
bus.register('orchestrator')
bus.register('worker-a')
bus.register('worker-b')

# Orchestrator sends a task to worker-a
bus.send(Message(
    sender='orchestrator',
    recipient='worker-a',
    performative='request',
    content={'task': 'search', 'query': 'recent AI safety papers'},
))

# worker-a receives and processes
msg = bus.receive('worker-a', block=True)
print('worker-a received:', msg.performative, msg.content)

# worker-a replies with result
bus.send(Message(
    sender='worker-a',
    recipient='orchestrator',
    performative='inform',
    content={'results': ['paper1', 'paper2']},
    reply_to=msg.performative,
))

result = bus.receive('orchestrator', block=True)
print('orchestrator received:', result.content)

