def research_agent(query):
    # In production this calls an LLM with a research system prompt
    return {'findings': ['Finding A about ' + query, 'Finding B about ' + query]}

def code_agent(spec):
    # In production this calls an LLM with a coding system prompt
    return {'code': 'def solution(): pass  # implements ' + spec}

def review_agent(code):
    return {'approved': True, 'comments': []}

# Orchestrator tool registry
AGENT_TOOLS = [
    {
