        'parameters': {'query': 'string'},
        'fn': research_agent,
    },
    {
        'name': 'code_agent',
        'description': 'Write code that satisfies a specification',
        'parameters': {'spec': 'string'},
        'fn': code_agent,
    },
    {
        'name': 'review_agent',
        'description': 'Review code for correctness and safety',
        'parameters': {'code': 'string'},
        'fn': review_agent,
    },
]

def orchestrator_run(task):
    # Step 1: gather context via research agent
    context = research_agent(task)
    print('Research findings:', context['findings'])

    # Step 2: produce implementation via code agent
    spec = task + ', context: ' + str(context['findings'])
    code_result = code_agent(spec)
    print('Code produced:', code_result['code'])

    # Step 3: review the code
    review = review_agent(code_result['code'])
    if review['approved']:
        print('Task complete -- code approved')
        return code_result['code']
    else:
        print('Review rejected:', review['comments'])
        return None

orchestrator_run('implement a rate limiter')

import json
from dataclasses import dataclass
from typing import Optional

@dataclass
class SafeMessage:
    sender: str
    recipient: str
    performative: str
    content: dict

ALLOWED_PERFORMATIVES = {'request', 'inform', 'query', 'confirm', 'refuse'}
MAX_CONTENT_SIZE = 64 * 1024  # 64 KB

def validate_message(msg):
    if msg.performative not in ALLOWED_PERFORMATIVES:
        raise ValueError('Unknown performative: ' + msg.performative)
    serialised = json.dumps(msg.content)
    if len(serialised.encode()) > MAX_CONTENT_SIZE:
        raise ValueError('Message content too large')
    # Never execute string fields as code
    for key, val in msg.content.items():
        if isinstance(val, str) and ('import ' in val or 'exec(' in val):
            raise ValueError('Suspicious content in field: ' + key)
    return True

class SafeWorkerAgent:
    def __init__(self, name, allowed_senders):
        self.name = name
        self.allowed_senders = allowed_senders  # whitelist

    def handle(self, msg):
        if msg.sender not in self.allowed_senders:
            return SafeMessage(
                sender=self.name,
                recipient=msg.sender,
                performative='refuse',
                content={'reason': 'sender not authorised'},
            )
        try:
            validate_message(msg)
        except ValueError as e:
            return SafeMessage(
                sender=self.name,
                recipient=msg.sender,
                performative='refuse',
                content={'reason': str(e)},
            )
        # Process the message
        result = self._process(msg.content)
        return SafeMessage(
            sender=self.name,
            recipient=msg.sender,
            performative='inform',
            content={'result': result},
        )

    def _process(self, content):
        return 'processed: ' + str(content.get('task', 'unknown'))

worker = SafeWorkerAgent('worker-a', allowed_senders={'orchestrator'})

good_msg = SafeMessage('orchestrator', 'worker-a', 'request', {'task': 'analyse logs'})
print(worker.handle(good_msg))

bad_sender = SafeMessage('rogue-agent', 'worker-a', 'request', {'task': 'delete all files'})
print(worker.handle(bad_sender))

import time
from dataclasses import dataclass
from typing import Optional

@dataclass
class Message:
    sender: str
    recipient: str
    performative: str
    content: dict
    msg_id: str = ''

class ReliableChannel:
    def __init__(self, timeout=10.0, max_retries=3, backoff=2.0):
        self.timeout = timeout
        self.max_retries = max_retries
        self.backoff = backoff

    def send_with_ack(self, msg, send_fn, receive_fn):
        delay = 1.0
        for attempt in range(1, self.max_retries + 1):
            send_fn(msg)
            # Wait for acknowledgement
            deadline = time.time() + self.timeout
            while time.time() < deadline:
                reply = receive_fn(timeout=0.5)
                if reply and reply.get('msg_id') == msg.msg_id:
                    if reply['performative'] == 'confirm':
                        return reply
                    elif reply['performative'] == 'refuse':
                        raise RuntimeError('Request refused: ' + str(reply.get('reason')))
            # Timeout — retry
            print('Attempt ' + str(attempt) + ' timed out, retrying in ' + str(delay) + 's')
            time.sleep(delay)
            delay *= self.backoff
        raise TimeoutError('No response after ' + str(self.max_retries) + ' attempts')

class RobustOrchestrator:
    def __init__(self, channel, workers):
        self.channel = channel
        self.workers = workers     # name -> send/receive functions
        self.pending = {}          # msg_id -> expected recipient

    def delegate(self, worker_name, task, msg_id):
        if worker_name not in self.workers:
            raise KeyError('Unknown worker: ' + worker_name)
        msg = Message(
            sender='orchestrator',
            recipient=worker_name,
            performative='request',
            content={'task': task},
            msg_id=msg_id,
        )
        send_fn, receive_fn = self.workers[worker_name]
        try:
            result = self.channel.send_with_ack(msg, send_fn, receive_fn)
            print('Task ' + msg_id + ' confirmed by ' + worker_name)
            return result
        except (TimeoutError, RuntimeError) as e:
            print('Delegation failed for ' + msg_id + ': ' + str(e))
            return None
